/* ai essentials :: content/quiz4.js  —  Domain 4 question bank (Conversational AI & Iteration) */
window.AIESS = window.AIESS || {}; AIESS.questions = AIESS.questions || [];
AIESS.questions.push(
  { id:"D4-001", domain:4, obj:"4.1", diff:"easy", q:"What is the BEST way to think about working with a chatbot like a modern AI assistant?", options:["A back-and-forth conversation where you refine the result over several turns","A one-shot vending machine where you insert a prompt and accept whatever comes out","A search engine that returns a fixed list of links","A calculator that gives one exact answer every time"], answer:0, explain:"<strong>A back-and-forth conversation where you refine the result over several turns</strong> is the mindset that gets the most out of a modern assistant, because it keeps the prior context and lets you steer.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>A one-shot vending machine where you insert a prompt and accept whatever comes out</b>: accepting the first output without iterating usually leaves easy improvements on the table.</span><span class='qd'><b>A search engine that returns a fixed list of links</b>: a chatbot generates tailored text you can shape further, unlike a static list of links.</span><span class='qd'><b>A calculator that gives one exact answer every time</b>: the assistant produces flexible drafts, not a single deterministic value, so treating it as fixed misses its strength.</span>" },
  { id:"D4-002", domain:4, obj:"4.1", diff:"easy", q:"You ask the AI to write a product description and the first draft is only okay. What is usually the MOST productive next step?", options:["Give up and write it yourself from scratch","Send a follow-up prompt telling the AI what to change","Send the same prompt again and hope for a better result","Copy the mediocre draft and use it as-is"], answer:1, explain:"<strong>Send a follow-up prompt telling the AI what to change</strong> keeps the conversation going and steers the next draft toward what you want.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Send the same prompt again and hope for a better result</b>: repeating an identical prompt gives the model no new direction, so results rarely improve meaningfully.</span><span class='qd'><b>Copy the mediocre draft and use it as-is</b>: settling for &quot;okay&quot; wastes the easy gains a single follow-up can deliver.</span><span class='qd'><b>Give up and write it yourself from scratch</b>: abandoning a usable draft discards work the AI already did that you could refine.</span>" },
  { id:"D4-003", domain:4, obj:"4.1", diff:"easy", q:"Why is the SECOND prompt in an AI conversation often the most important one?", options:["The AI forgets everything after the first prompt anyway","Every AI charges more for the first prompt","It is where you correct and refine the first answer toward your real goal","The first prompt is always ignored by the model"], answer:2, explain:"<strong>It is where you correct and refine the first answer toward your real goal</strong> because the first answer is a starting point, and the follow-up is where you close the gap.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>The AI forgets everything after the first prompt anyway</b>: within a single thread the assistant retains the earlier turns, which is exactly what makes the second prompt effective.</span><span class='qd'><b>Every AI charges more for the first prompt</b>: importance here is about steering quality, not pricing.</span><span class='qd'><b>The first prompt is always ignored by the model</b>: the first prompt is used to produce the first answer; it is not ignored.</span>" },
  { id:"D4-004", domain:4, obj:"4.1", diff:"easy", q:"Which of the following is a realistic expectation when you send your first prompt to an AI assistant?", options:["The first answer will always be perfect and final","The AI can only ever respond once per topic","The AI will refuse to answer without payment","The first answer is a draft you will likely refine"], answer:3, explain:"<strong>The first answer is a draft you will likely refine</strong> sets the right expectation, since first responses are starting points rather than finished products.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>The first answer will always be perfect and final</b>: first drafts commonly need clarification, added detail, or a revision pass.</span><span class='qd'><b>The AI will refuse to answer without payment</b>: this is unrelated to how iteration works and is not a general behavior of assistants.</span><span class='qd'><b>The AI can only ever respond once per topic</b>: assistants are built for multi-turn dialogue, so many follow-ups on one topic are normal.</span>" },
  { id:"D4-005", domain:4, obj:"4.1", diff:"easy", q:"An AI assistant that keeps track of what you said earlier in the same chat is demonstrating which capability?", options:["Conversational context","Image generation","Spell checking","Internet browsing"], answer:0, explain:"<strong>Conversational context</strong> is the ability to remember earlier turns in the same thread so later replies build on them.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Image generation</b>: creating pictures is a separate feature and does not describe remembering the dialogue.</span><span class='qd'><b>Spell checking</b>: correcting spelling is unrelated to retaining what was said earlier.</span><span class='qd'><b>Internet browsing</b>: fetching live web pages is a different capability from tracking the ongoing conversation.</span>" },
  { id:"D4-006", domain:4, obj:"4.1", diff:"medium", q:"You are drafting an email with the AI and mention &quot;the client I told you about earlier.&quot; The AI correctly recalls the client's name from a message three turns ago. This works because the AI is using:", options:["A saved permanent profile of you","The conversation history within the current thread","A public database of all clients","Your device's contact list"], answer:1, explain:"<strong>The conversation history within the current thread</strong> lets the assistant reference details you provided earlier in the same chat.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>A saved permanent profile of you</b>: the recall here comes from this thread's messages, not a stored profile that persists across chats.</span><span class='qd'><b>A public database of all clients</b>: the assistant is not looking your client up externally; it read the name from your earlier message.</span><span class='qd'><b>Your device's contact list</b>: a chatbot does not pull from your phone contacts to recall something you typed in the conversation.</span>" },
  { id:"D4-007", domain:4, obj:"4.1", diff:"medium", q:"Which statement BEST captures the difference between a one-shot transaction and a multi-turn conversation with AI?", options:["A conversation can only ever have two messages total","A one-shot is always more accurate than a conversation","A one-shot ends after a single exchange; a conversation refines the result over multiple exchanges","There is no practical difference between them"], answer:2, explain:"<strong>A one-shot ends after a single exchange; a conversation refines the result over multiple exchanges</strong> is the core distinction and explains why iterating tends to produce better outcomes.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>A one-shot is always more accurate than a conversation</b>: iterating usually improves accuracy and fit, so a single shot is not inherently better.</span><span class='qd'><b>A conversation can only ever have two messages total</b>: conversations can run many turns, not just two.</span><span class='qd'><b>There is no practical difference between them</b>: the ability to refine over turns is a meaningful, practical difference.</span>" },
  { id:"D4-008", domain:4, obj:"4.1", diff:"medium", q:"A colleague says, &quot;I always accept the AI's first answer to save time.&quot; What is the MOST accurate response about this habit?", options:["It is ideal because first answers are always best","It prevents the AI from ever making mistakes","It guarantees the answer is factually correct","It often leaves quality on the table that a quick follow-up could capture"], answer:3, explain:"<strong>It often leaves quality on the table that a quick follow-up could capture</strong> because a single refining prompt frequently improves tone, accuracy, or fit at little cost.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>It is ideal because first answers are always best</b>: first answers are drafts and are not reliably the best possible output.</span><span class='qd'><b>It guarantees the answer is factually correct</b>: accepting a first answer does nothing to verify facts and can preserve errors.</span><span class='qd'><b>It prevents the AI from ever making mistakes</b>: not iterating cannot prevent mistakes; it may simply leave them uncorrected.</span>" },
  { id:"D4-009", domain:4, obj:"4.1", diff:"medium", q:"You realize halfway through a chat that the AI has been assuming your audience is technical experts, but it is actually beginners. What does treating AI as a conversation let you do here?", options:["Send a follow-up that corrects the audience assumption and have it revise from there","Nothing; you must start a brand-new chat to change anything","Only accept the wrong-audience output","Delete the AI and reinstall it"], answer:0, explain:"<strong>Send a follow-up that corrects the audience assumption and have it revise from there</strong> is the whole point of iterating: you fix the misunderstanding without losing the prior work.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Nothing; you must start a brand-new chat to change anything</b>: a follow-up in the same thread can correct course while keeping context.</span><span class='qd'><b>Only accept the wrong-audience output</b>: settling for content aimed at the wrong readers defeats the purpose of iterating.</span><span class='qd'><b>Delete the AI and reinstall it</b>: reinstalling has nothing to do with correcting an assumption inside a conversation.</span>" },
  { id:"D4-010", domain:4, obj:"4.1", diff:"medium", q:"Which scenario BEST illustrates building output on output across a conversation?", options:["Asking the same question five times in a row","Having the AI outline an article, then expand the approved outline into full sections","Opening five separate chats and asking one thing in each","Refusing to read the AI's responses"], answer:1, explain:"<strong>Having the AI outline an article, then expand the approved outline into full sections</strong> uses one result as the foundation for the next, which is building output on output.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Asking the same question five times in a row</b>: repetition does not build on a prior result; each try starts over.</span><span class='qd'><b>Opening five separate chats and asking one thing in each</b>: separate chats do not share context, so nothing is built upon.</span><span class='qd'><b>Refusing to read the AI's responses</b>: you cannot build on output you never review.</span>" },
  { id:"D4-011", domain:4, obj:"4.1", diff:"medium", q:"An AI produces a solid summary of a report. You now want a shorter version for executives. What is the advantage of asking in the SAME thread rather than a new chat?", options:["The new chat would be faster to load","New chats always give better writing","The same thread already has the report and summary as context to condense","The same thread hides your history from you"], answer:2, explain:"<strong>The same thread already has the report and summary as context to condense</strong>, so the AI can shorten what it already understands without re-explaining everything.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>The new chat would be faster to load</b>: load speed is not the relevant benefit, and a fresh chat loses the needed context.</span><span class='qd'><b>New chats always give better writing</b>: writing quality is not improved by discarding the context you need.</span><span class='qd'><b>The same thread hides your history from you</b>: staying in the thread preserves and shows the history, it does not hide it.</span>" },
  { id:"D4-012", domain:4, obj:"4.1", diff:"hard", q:"You have spent 15 turns refining a marketing plan, and the AI now seems confused, mixing up earlier decisions and contradicting itself. The thread is very long. What is the BEST move?", options:["Keep pushing in the same thread and hope it recovers","Send an empty message to reset it","Abandon the AI entirely for this task","Summarize the final decisions, then start a fresh chat seeded with that clean summary"], answer:3, explain:"<strong>Summarize the final decisions, then start a fresh chat seeded with that clean summary</strong> gives the model a tidy, unambiguous starting context and clears the accumulated confusion.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Keep pushing in the same thread and hope it recovers</b>: a cluttered thread that is already contradicting itself tends to stay confused, so continuing rarely helps.</span><span class='qd'><b>Abandon the AI entirely for this task</b>: the work so far is valuable; carrying a summary forward is far better than quitting.</span><span class='qd'><b>Send an empty message to reset it</b>: an empty message does not reset context and provides no useful direction.</span>" },
  { id:"D4-013", domain:4, obj:"4.1", diff:"hard", q:"A teammate keeps ALL of their unrelated tasks (budget math, a poem, a legal summary, and vacation ideas) in one endless chat. Why can this HURT the quality of responses over time?", options:["Mixing many unrelated topics clutters the context and can bleed irrelevant details into answers","Chats have a strict two-topic maximum enforced by law","The AI charges extra after four topics","Long chats automatically delete correct answers"], answer:0, explain:"<strong>Mixing many unrelated topics clutters the context and can bleed irrelevant details into answers</strong>, so a focused new thread often yields cleaner results.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Chats have a strict two-topic maximum enforced by law</b>: there is no legal topic limit; the issue is practical context clutter.</span><span class='qd'><b>The AI charges extra after four topics</b>: the problem is coherence, not a per-topic fee.</span><span class='qd'><b>Long chats automatically delete correct answers</b>: length does not delete prior correct answers; it can just dilute focus.</span>" },
  { id:"D4-014", domain:4, obj:"4.1", diff:"hard", q:"You want the AI to help you plan, draft, and then proofread a newsletter. Which approach BEST uses the conversational nature of the tool?", options:["Ask for the finished, proofread newsletter in a single prompt and accept it","Work in stages within one thread: agree on a plan, draft from it, then request a proofreading pass","Use three different AI tools that cannot see each other's work","Never tell the AI what the newsletter is about"], answer:1, explain:"<strong>Work in stages within one thread: agree on a plan, draft from it, then request a proofreading pass</strong> lets each step build on the last while the AI retains full context.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Ask for the finished, proofread newsletter in a single prompt and accept it</b>: cramming plan, draft, and proofing into one shot skips the refinement that improves each stage.</span><span class='qd'><b>Use three different AI tools that cannot see each other's work</b>: splitting across disconnected tools throws away the shared context that makes staging effective.</span><span class='qd'><b>Never tell the AI what the newsletter is about</b>: withholding the topic starves every stage of the context it needs.</span>" },
  { id:"D4-015", domain:4, obj:"4.1", diff:"hard", q:"Which of the following is the STRONGEST sign that you should start a fresh conversation rather than continue the current one?", options:["The AI gave you a good answer on the first try","You want to slightly reword your last request","The topic has completely changed and the old context is now irrelevant and distracting","You are happy with the direction of the thread"], answer:2, explain:"<strong>The topic has completely changed and the old context is now irrelevant and distracting</strong> is a clear cue to start fresh so stale context does not skew the new task.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>The AI gave you a good answer on the first try</b>: a good first answer is a reason to continue or stop, not to abandon the thread.</span><span class='qd'><b>You want to slightly reword your last request</b>: a small rewording is exactly what a follow-up in the same thread handles well.</span><span class='qd'><b>You are happy with the direction of the thread</b>: satisfaction with the direction argues for staying in the thread, not leaving it.</span>" },
  { id:"D4-016", domain:4, obj:"4.1", diff:"easy", q:"Iterating with an AI means:", options:["Repeating the exact same prompt with no changes","Ignoring the AI's responses entirely","Turning the AI off and on again","Refining your request across turns based on what the AI produced"], answer:3, explain:"<strong>Refining your request across turns based on what the AI produced</strong> is the definition of iterating, using each response to inform the next prompt.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Repeating the exact same prompt with no changes</b>: identical repetition provides no new direction and is not iteration.</span><span class='qd'><b>Turning the AI off and on again</b>: restarting the tool is unrelated to refining a request.</span><span class='qd'><b>Ignoring the AI's responses entirely</b>: iteration depends on reading and reacting to responses.</span>" },
  { id:"D4-017", domain:4, obj:"4.1", diff:"easy", q:"After the AI answers, which mindset leads to better final results?", options:["&quot;This is a starting point I can improve with a follow-up.&quot;","&quot;This is the only answer I will ever get.&quot;","&quot;I should never respond again.&quot;","&quot;The answer cannot be changed.&quot;"], answer:0, explain:"<strong>&quot;This is a starting point I can improve with a follow-up.&quot;</strong> keeps you open to refining, which is how conversations reach strong results.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>&quot;This is the only answer I will ever get.&quot;</b>: assistants support many follow-ups, so this framing needlessly stops improvement.</span><span class='qd'><b>&quot;I should never respond again.&quot;</b>: refusing to respond ends the iteration that improves output.</span><span class='qd'><b>&quot;The answer cannot be changed.&quot;</b>: a follow-up can change and improve the answer, so this belief is inaccurate.</span>" },
  { id:"D4-018", domain:4, obj:"4.1", diff:"medium", q:"A user opens a new chat every single time they want to tweak the AI's previous answer, then re-pastes the whole answer each time. What is the DOWNSIDE of this workflow?", options:["It preserves context perfectly","It wastes effort re-supplying context the AI would already have in one thread","It is the only way AI can function","It makes the AI faster"], answer:1, explain:"<strong>It wastes effort re-supplying context the AI would already have in one thread</strong>, since staying in the thread lets the AI keep the prior answer automatically.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>It preserves context perfectly</b>: it actually forces manual re-pasting because the new chat lacks the prior context.</span><span class='qd'><b>It is the only way AI can function</b>: assistants handle follow-ups within a single thread, so new chats are not required.</span><span class='qd'><b>It makes the AI faster</b>: re-pasting large context each time adds effort and does not speed things up.</span>" },
  { id:"D4-019", domain:4, obj:"4.1", diff:"medium", q:"Which of these BEST describes &quot;maintaining continuity&quot; in an AI conversation?", options:["Using a different language in each message","Deleting every message after you read it","Keeping related requests in one thread so earlier context carries forward","Never referencing anything you said before"], answer:2, explain:"<strong>Keeping related requests in one thread so earlier context carries forward</strong> is what continuity means, letting later turns rely on what came before.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Deleting every message after you read it</b>: removing messages destroys the continuity you are trying to keep.</span><span class='qd'><b>Using a different language in each message</b>: switching languages does not create continuity and can add confusion.</span><span class='qd'><b>Never referencing anything you said before</b>: continuity depends on building on prior turns, not avoiding them.</span>" },
  { id:"D4-020", domain:4, obj:"4.1", diff:"medium", q:"You ask the AI a question, get an answer, and then ask three increasingly specific follow-ups that each improve the result. This pattern is BEST called:", options:["A one-shot query","A hard reset","A hallucination","Iterative refinement"], answer:3, explain:"<strong>Iterative refinement</strong> describes progressively improving the output through successive, more specific follow-ups.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>A one-shot query</b>: a one-shot is a single exchange, not a series of improving follow-ups.</span><span class='qd'><b>A hallucination</b>: a hallucination is a confident but false statement from the AI, unrelated to your refining pattern.</span><span class='qd'><b>A hard reset</b>: a reset clears context, which is the opposite of building through follow-ups.</span>" },
  { id:"D4-021", domain:4, obj:"4.2", diff:"easy", q:"The AI's answer mentions a term you do not recognize. What is a good conversational move before continuing?", options:["Ask the AI to explain that term in simple language","Ignore the term and hope it does not matter","Immediately start a new chat","Assume the AI made the word up and stop using it"], answer:0, explain:"<strong>Ask the AI to explain that term in simple language</strong> is the clarifying move that ensures you understand the response before building on it.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Ignore the term and hope it does not matter</b>: proceeding without understanding risks building on a misconception.</span><span class='qd'><b>Immediately start a new chat</b>: a new chat is unnecessary and loses the context where the term appeared.</span><span class='qd'><b>Assume the AI made the word up and stop using it</b>: assuming it is invented, rather than asking, skips a quick, useful clarification.</span>" },
  { id:"D4-022", domain:4, obj:"4.2", diff:"easy", q:"Which of the following is an example of asking a clarifying question of the AI?", options:["&quot;Make it longer.&quot;","&quot;What do you mean by &lsquo;engagement rate&rsquo; in this answer?&quot;","&quot;Change the tone to formal.&quot;","&quot;Add three more examples.&quot;"], answer:1, explain:"<strong>&quot;What do you mean by &lsquo;engagement rate&rsquo; in this answer?&quot;</strong> seeks to understand something in the response, which is the essence of a clarifying question.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>&quot;Make it longer.&quot;</b>: this changes the output rather than seeking understanding, so it adds an element instead of clarifying.</span><span class='qd'><b>&quot;Change the tone to formal.&quot;</b>: adjusting tone is a style change, not a request to understand the response.</span><span class='qd'><b>&quot;Add three more examples.&quot;</b>: adding examples expands the content instead of clarifying the meaning of what was said.</span>" },
  { id:"D4-023", domain:4, obj:"4.2", diff:"easy", q:"Clarifying questions are MOST useful when:", options:["You fully understand every part of the answer already","You want the AI to write more text","Part of the AI's answer is unclear and you need to understand it before acting","You are ready to end the conversation"], answer:2, explain:"<strong>Part of the AI's answer is unclear and you need to understand it before acting</strong> is exactly when a clarifying question pays off.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>You fully understand every part of the answer already</b>: if nothing is unclear, there is nothing to clarify.</span><span class='qd'><b>You want the AI to write more text</b>: wanting more text is an add-elements move, not a clarification.</span><span class='qd'><b>You are ready to end the conversation</b>: ending the chat is the opposite of pausing to clarify something.</span>" },
  { id:"D4-024", domain:4, obj:"4.2", diff:"easy", q:"The AI gives you a step-by-step process but step 3 is vague. What is the BEST clarifying follow-up?", options:["&quot;Rewrite the whole thing in a different style.&quot;","&quot;Make the whole answer shorter.&quot;","&quot;Delete step 3 entirely.&quot;","&quot;Can you explain step 3 in more detail so I know exactly what to do?&quot;"], answer:3, explain:"<strong>&quot;Can you explain step 3 in more detail so I know exactly what to do?&quot;</strong> targets the unclear part and asks the AI to make it understandable.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>&quot;Rewrite the whole thing in a different style.&quot;</b>: restyling everything does not clarify the specific step you did not understand.</span><span class='qd'><b>&quot;Delete step 3 entirely.&quot;</b>: removing the step avoids the confusion instead of resolving it, and you may need that step.</span><span class='qd'><b>&quot;Make the whole answer shorter.&quot;</b>: shortening the answer is likely to make the vague step even less clear.</span>" },
  { id:"D4-025", domain:4, obj:"4.2", diff:"medium", q:"You asked the AI to recommend a &quot;low-code&quot; tool but you are not sure what &quot;low-code&quot; means. What should you do FIRST to get the most value?", options:["Ask the AI what &quot;low-code&quot; means so you can judge the recommendation","Pick a random recommendation without understanding it","Tell the AI it is wrong","Switch to a completely different topic"], answer:0, explain:"<strong>Ask the AI what &quot;low-code&quot; means so you can judge the recommendation</strong> ensures you understand the concept before acting on advice built around it.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Pick a random recommendation without understanding it</b>: choosing blindly means you cannot tell whether the tool actually fits your needs.</span><span class='qd'><b>Tell the AI it is wrong</b>: you have no basis to say it is wrong until you understand the term, so this is premature.</span><span class='qd'><b>Switch to a completely different topic</b>: abandoning the topic leaves your original question unanswered and your confusion unresolved.</span>" },
  { id:"D4-026", domain:4, obj:"4.2", diff:"medium", q:"An AI's answer includes the phrase &quot;subject to standard indemnification.&quot; You do not work in law. Which follow-up BEST helps you before you rely on the answer?", options:["&quot;Add more legal jargon to sound professional.&quot;","&quot;In plain English, what does &lsquo;standard indemnification&rsquo; mean here?&quot;","&quot;Ignore that sentence.&quot;","&quot;Translate the whole thing into French.&quot;"], answer:1, explain:"<strong>&quot;In plain English, what does &lsquo;standard indemnification&rsquo; mean here?&quot;</strong> asks the AI to translate an unfamiliar term so you can evaluate the answer responsibly.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>&quot;Add more legal jargon to sound professional.&quot;</b>: piling on jargon makes the answer harder to understand, not clearer.</span><span class='qd'><b>&quot;Ignore that sentence.&quot;</b>: ignoring a term you must rely on can leave you exposed to something important you did not grasp.</span><span class='qd'><b>&quot;Translate the whole thing into French.&quot;</b>: translating languages does not explain the meaning of a specialized legal phrase.</span>" },
  { id:"D4-027", domain:4, obj:"4.2", diff:"medium", q:"Why is it risky to keep asking the AI to build on an answer that contains a concept you do not understand?", options:["The AI will refuse to continue","It always costs extra money","You may compound a misunderstanding into later steps without realizing it","The AI will delete the earlier answer"], answer:2, explain:"<strong>You may compound a misunderstanding into later steps without realizing it</strong>, which is why clarifying first protects the whole chain of work.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>The AI will refuse to continue</b>: the AI will keep going whether or not you understand, which is precisely the risk.</span><span class='qd'><b>It always costs extra money</b>: the danger is conceptual error, not an automatic fee.</span><span class='qd'><b>The AI will delete the earlier answer</b>: continuing does not erase prior answers; it just builds on possibly misunderstood ones.</span>" },
  { id:"D4-028", domain:4, obj:"4.2", diff:"medium", q:"Which follow-up is a clarifying question rather than an instruction to change the output?", options:["&quot;Shorten this to one paragraph.&quot;","&quot;Add a table of the results.&quot;","&quot;Rewrite it for a younger audience.&quot;","&quot;Why did you recommend option B over option A?&quot;"], answer:3, explain:"<strong>&quot;Why did you recommend option B over option A?&quot;</strong> asks the AI to explain its reasoning, which clarifies the response rather than altering it.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>&quot;Shorten this to one paragraph.&quot;</b>: shortening changes the output, so it is an add-elements or constraint move, not clarification.</span><span class='qd'><b>&quot;Rewrite it for a younger audience.&quot;</b>: changing the audience rewrites the content instead of seeking understanding.</span><span class='qd'><b>&quot;Add a table of the results.&quot;</b>: adding a table modifies the output rather than clarifying the meaning of the answer.</span>" },
  { id:"D4-029", domain:4, obj:"4.2", diff:"medium", q:"The AI gives an answer that seems to contradict something it said two turns ago. What is a reasonable clarifying follow-up?", options:["&quot;Earlier you said X, but now you say Y. Which is correct and why?&quot;","&quot;You are useless.&quot;","&quot;Start over and forget everything.&quot;","&quot;Make it rhyme.&quot;"], answer:0, explain:"<strong>&quot;Earlier you said X, but now you say Y. Which is correct and why?&quot;</strong> surfaces the contradiction and asks the AI to resolve it, improving reliability.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>&quot;You are useless.&quot;</b>: an insult gives the AI no information to reconcile the two statements.</span><span class='qd'><b>&quot;Start over and forget everything.&quot;</b>: resetting discards useful context and does not explain the inconsistency.</span><span class='qd'><b>&quot;Make it rhyme.&quot;</b>: a stylistic change ignores the contradiction you actually need resolved.</span>" },
  { id:"D4-030", domain:4, obj:"4.2", diff:"hard", q:"You are a non-expert reviewing an AI-written technical proposal for your manager. Several sentences use acronyms you cannot verify. What is the MOST responsible clarifying approach before forwarding it?", options:["Forward it as-is and hope the manager understands the acronyms","Ask the AI to define each acronym and confirm they are used correctly, then verify the key ones yourself","Delete every sentence with an acronym","Replace all acronyms with question marks"], answer:1, explain:"<strong>Ask the AI to define each acronym and confirm they are used correctly, then verify the key ones yourself</strong> combines clarification with independent verification, which is responsible use.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Forward it as-is and hope the manager understands the acronyms</b>: forwarding unverified content you do not understand risks passing along errors under your name.</span><span class='qd'><b>Delete every sentence with an acronym</b>: deleting content wholesale can remove important substance instead of clarifying it.</span><span class='qd'><b>Replace all acronyms with question marks</b>: hiding the acronyms does not resolve whether they are correct and makes the document unusable.</span>" },
  { id:"D4-031", domain:4, obj:"4.2", diff:"hard", q:"The AI explains a recommendation using an analogy you do not find helpful, and you still do not understand the underlying point. Which clarifying sequence is BEST?", options:["Accept the analogy even though it did not help","Tell the AI to stop explaining","Ask the AI to re-explain the point a different way, ideally with a concrete example from your industry","Ask for the same analogy again word for word"], answer:2, explain:"<strong>Ask the AI to re-explain the point a different way, ideally with a concrete example from your industry</strong> steers toward an explanation that actually clicks for you.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Accept the analogy even though it did not help</b>: accepting an unhelpful explanation leaves you still not understanding the point.</span><span class='qd'><b>Tell the AI to stop explaining</b>: cutting off the explanation guarantees you never grasp the concept.</span><span class='qd'><b>Ask for the same analogy again word for word</b>: repeating the analogy that already failed is unlikely to help.</span>" },
  { id:"D4-032", domain:4, obj:"4.2", diff:"hard", q:"During a research chat, the AI cites a statistic that would strongly influence your decision. You do not understand how it was derived. What is the BEST next step in the conversation?", options:["Use the statistic immediately because it supports your view","Ask the AI to make the number bigger","Assume the number is fine and move on","Ask the AI to explain where the number comes from and how it was calculated, then verify it independently"], answer:3, explain:"<strong>Ask the AI to explain where the number comes from and how it was calculated, then verify it independently</strong> clarifies the claim and guards against acting on an unverified figure.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Use the statistic immediately because it supports your view</b>: agreeing because it flatters your view is confirmation bias and skips verification.</span><span class='qd'><b>Assume the number is fine and move on</b>: assuming correctness on a decision-critical figure is exactly the risk clarifying is meant to reduce.</span><span class='qd'><b>Ask the AI to make the number bigger</b>: altering the figure to suit you fabricates data rather than clarifying it.</span>" },
  { id:"D4-033", domain:4, obj:"4.2", diff:"medium", q:"Which of these is the CLEAREST example of clarifying to understand, not to change the output?", options:["&quot;Can you walk me through how you arrived at this recommendation?&quot;","&quot;Add a conclusion paragraph.&quot;","&quot;Use bullet points instead of paragraphs.&quot;","&quot;Make the tone friendlier.&quot;"], answer:0, explain:"<strong>&quot;Can you walk me through how you arrived at this recommendation?&quot;</strong> asks the AI to reveal its reasoning so you understand the answer, without changing it.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>&quot;Add a conclusion paragraph.&quot;</b>: adding a paragraph changes the output rather than seeking understanding.</span><span class='qd'><b>&quot;Use bullet points instead of paragraphs.&quot;</b>: reformatting is a change to the output, not a clarification.</span><span class='qd'><b>&quot;Make the tone friendlier.&quot;</b>: adjusting tone alters the response instead of explaining it.</span>" },
  { id:"D4-034", domain:4, obj:"4.2", diff:"easy", q:"If you do not understand WHY the AI gave a certain recommendation, the best conversational move is to:", options:["Assume it is correct and act on it","Ask the AI to explain its reasoning","End the chat","Ask an unrelated question"], answer:1, explain:"<strong>Ask the AI to explain its reasoning</strong> lets you evaluate whether the recommendation actually makes sense for you.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Assume it is correct and act on it</b>: acting without understanding the reasoning risks following flawed advice.</span><span class='qd'><b>End the chat</b>: ending the conversation abandons the question you still have.</span><span class='qd'><b>Ask an unrelated question</b>: changing subjects leaves your uncertainty about the recommendation unresolved.</span>" },
  { id:"D4-035", domain:4, obj:"4.2", diff:"medium", q:"You get a list of recommendations but are unsure which one applies to a small business like yours. What is the BEST clarifying follow-up?", options:["&quot;Rewrite the list as a poem.&quot;","&quot;Give me twice as many recommendations.&quot;","&quot;Of these, which best fits a small business with 10 employees, and why?&quot;","&quot;Change the font.&quot;"], answer:2, explain:"<strong>&quot;Of these, which best fits a small business with 10 employees, and why?&quot;</strong> asks the AI to clarify how its answer maps to your specific situation.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>&quot;Rewrite the list as a poem.&quot;</b>: a stylistic rewrite does not help you understand which item fits your business.</span><span class='qd'><b>&quot;Give me twice as many recommendations.&quot;</b>: more options add confusion without clarifying which one applies to you.</span><span class='qd'><b>&quot;Change the font.&quot;</b>: formatting has nothing to do with clarifying relevance to a small business.</span>" },
  { id:"D4-036", domain:4, obj:"4.3", diff:"easy", q:"The AI's first draft is too generic. Which follow-up is an example of ADDING CONTEXT to improve it?", options:["&quot;Try again.&quot;","&quot;Why is it generic?&quot;","&quot;Make it perfect.&quot;","&quot;This is for first-year nursing students preparing for their first clinical rotation.&quot;"], answer:3, explain:"<strong>&quot;This is for first-year nursing students preparing for their first clinical rotation.&quot;</strong> supplies audience and situation, which is added context that helps the AI tailor the draft.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>&quot;Try again.&quot;</b>: this gives no new information, so the AI has nothing to specialize toward.</span><span class='qd'><b>&quot;Make it perfect.&quot;</b>: a vague demand adds no context and does not tell the AI what to change.</span><span class='qd'><b>&quot;Why is it generic?&quot;</b>: this is a clarifying question, not the addition of context to the request.</span>" },
  { id:"D4-037", domain:4, obj:"4.3", diff:"easy", q:"Which follow-up adds a CONSTRAINT to the AI's next response?", options:["&quot;Keep the summary under 100 words.&quot;","&quot;Tell me more.&quot;","&quot;What does this mean?&quot;","&quot;Is this correct?&quot;"], answer:0, explain:"<strong>&quot;Keep the summary under 100 words.&quot;</strong> sets a clear boundary on the output, which is a constraint.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>&quot;Tell me more.&quot;</b>: this expands the answer rather than constraining it.</span><span class='qd'><b>&quot;What does this mean?&quot;</b>: this is a clarifying question, not a constraint.</span><span class='qd'><b>&quot;Is this correct?&quot;</b>: this asks for verification and imposes no boundary on the output.</span>" },
  { id:"D4-038", domain:4, obj:"4.3", diff:"easy", q:"Which follow-up changes the FORMAT of the AI's output?", options:["&quot;Explain your reasoning.&quot;","&quot;Present this as a bulleted checklist instead of paragraphs.&quot;","&quot;Who is the audience?&quot;","&quot;Double-check your facts.&quot;"], answer:1, explain:"<strong>&quot;Present this as a bulleted checklist instead of paragraphs.&quot;</strong> requests a specific structure, which is a format change.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>&quot;Explain your reasoning.&quot;</b>: this asks for justification, not a different format.</span><span class='qd'><b>&quot;Who is the audience?&quot;</b>: this is a clarifying question, not a formatting instruction.</span><span class='qd'><b>&quot;Double-check your facts.&quot;</b>: this requests verification and does not change the output's structure.</span>" },
  { id:"D4-039", domain:4, obj:"4.3", diff:"easy", q:"Which follow-up changes the STYLE or TONE of the response?", options:["&quot;Verify the third point.&quot;","&quot;How long is this?&quot;","&quot;Rewrite this in a warm, encouraging tone.&quot;","&quot;What did you mean earlier?&quot;"], answer:2, explain:"<strong>&quot;Rewrite this in a warm, encouraging tone.&quot;</strong> directs the AI to adjust the voice of the writing, which is a style and tone change.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>&quot;How long is this?&quot;</b>: this asks about length and does not change tone.</span><span class='qd'><b>&quot;Verify the third point.&quot;</b>: this requests checking, not a tone adjustment.</span><span class='qd'><b>&quot;What did you mean earlier?&quot;</b>: this is a clarifying question, not a style change.</span>" },
  { id:"D4-040", domain:4, obj:"4.3", diff:"medium", q:"The AI wrote a good cover letter but it does not mention your five years of project-management experience. Which follow-up BEST improves it?", options:["&quot;Make it better.&quot;","&quot;Shorten it.&quot;","&quot;Why did you leave things out?&quot;","&quot;Revise it to highlight my five years of project-management experience.&quot;"], answer:3, explain:"<strong>&quot;Revise it to highlight my five years of project-management experience.&quot;</strong> adds a specific detail for the AI to weave in, directly improving relevance.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>&quot;Make it better.&quot;</b>: this is vague and gives the AI no specific detail to incorporate.</span><span class='qd'><b>&quot;Why did you leave things out?&quot;</b>: this clarifies but does not add the missing experience to the letter.</span><span class='qd'><b>&quot;Shorten it.&quot;</b>: shortening could remove even more, and it does not add your experience.</span>" },
  { id:"D4-041", domain:4, obj:"4.3", diff:"medium", q:"You want the AI's marketing copy to sound less corporate. Which follow-up adds the RIGHT kind of detail to steer it?", options:["&quot;Make it conversational and playful, like a friend recommending a favorite product.&quot;","&quot;Change it.&quot;","&quot;Is it corporate?&quot;","&quot;Add more words.&quot;"], answer:0, explain:"<strong>&quot;Make it conversational and playful, like a friend recommending a favorite product.&quot;</strong> gives a concrete tone target the AI can aim for.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>&quot;Change it.&quot;</b>: this does not say how to change it, so the result is unpredictable.</span><span class='qd'><b>&quot;Is it corporate?&quot;</b>: this asks a yes/no question and gives no direction for the rewrite.</span><span class='qd'><b>&quot;Add more words.&quot;</b>: more words will not necessarily make the copy less corporate.</span>" },
  { id:"D4-042", domain:4, obj:"4.3", diff:"medium", q:"Which follow-up combines an ADDED CONSTRAINT with a FORMAT change in a single, useful prompt?", options:["&quot;Tell me about tips.&quot;","&quot;Give me the top 5 tips as a numbered list, each under 20 words.&quot;","&quot;What are tips?&quot;","&quot;Explain why tips matter.&quot;"], answer:1, explain:"<strong>&quot;Give me the top 5 tips as a numbered list, each under 20 words.&quot;</strong> sets both a length constraint and a numbered-list format, tightening the output usefully.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>&quot;Tell me about tips.&quot;</b>: this is open-ended with no constraint or format specified.</span><span class='qd'><b>&quot;What are tips?&quot;</b>: this is a definitional question, not a constrained, formatted request.</span><span class='qd'><b>&quot;Explain why tips matter.&quot;</b>: this asks for justification and specifies neither format nor limits.</span>" },
  { id:"D4-043", domain:4, obj:"4.3", diff:"medium", q:"The AI's answer is accurate but written at a graduate reading level for an audience of 10-year-olds. Which follow-up BEST fixes the mismatch?", options:["&quot;Add citations.&quot;","&quot;Make it longer and more technical.&quot;","&quot;Rewrite this so a 10-year-old can easily understand it.&quot;","&quot;Why is it hard to read?&quot;"], answer:2, explain:"<strong>&quot;Rewrite this so a 10-year-old can easily understand it.&quot;</strong> adds the audience constraint the AI needs to adjust vocabulary and complexity.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>&quot;Add citations.&quot;</b>: citations do not lower the reading level for a young audience.</span><span class='qd'><b>&quot;Make it longer and more technical.&quot;</b>: this makes the mismatch worse, not better.</span><span class='qd'><b>&quot;Why is it hard to read?&quot;</b>: this clarifies but does not instruct the AI to simplify the text.</span>" },
  { id:"D4-044", domain:4, obj:"4.3", diff:"medium", q:"You provided no examples in your first prompt and got a bland result. Which follow-up applies the ADD ELEMENTS technique MOST effectively?", options:["&quot;Do it again but better.&quot;","&quot;Make it shorter.&quot;","&quot;Why is it bland?&quot;","&quot;Here are two examples of the style I want; match this voice.&quot;"], answer:3, explain:"<strong>&quot;Here are two examples of the style I want; match this voice.&quot;</strong> supplies concrete models, giving the AI a target to imitate.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>&quot;Do it again but better.&quot;</b>: this adds no example or direction, so the AI cannot tell what &quot;better&quot; means.</span><span class='qd'><b>&quot;Why is it bland?&quot;</b>: this is a clarifying question and does not provide a style to follow.</span><span class='qd'><b>&quot;Make it shorter.&quot;</b>: length is unrelated to the blandness caused by missing style examples.</span>" },
  { id:"D4-045", domain:4, obj:"4.3", diff:"hard", q:"An AI drafted a policy document that is thorough but ignores your company's remote-work culture and its strict data-privacy obligations. Which single follow-up BEST steers the revision?", options:["&quot;Revise it for a fully remote company that must comply with strict data-privacy rules, and flag any section affected by those rules.&quot;","&quot;Make it sound more official.&quot;","&quot;Shorten every paragraph.&quot;","&quot;Why didn't you mention remote work?&quot;"], answer:0, explain:"<strong>&quot;Revise it for a fully remote company that must comply with strict data-privacy rules, and flag any section affected by those rules.&quot;</strong> adds the missing context and constraints and asks the AI to surface the impacted parts.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>&quot;Make it sound more official.&quot;</b>: tone does not address the missing remote-work and privacy requirements.</span><span class='qd'><b>&quot;Shorten every paragraph.&quot;</b>: shortening does not add the needed context and could cut relevant material.</span><span class='qd'><b>&quot;Why didn't you mention remote work?&quot;</b>: this clarifies the omission but does not instruct the AI to fix it.</span>" },
  { id:"D4-046", domain:4, obj:"4.3", diff:"hard", q:"You are iterating on a sales email. Each follow-up you send is a single vague word like &quot;better&quot; or &quot;stronger.&quot; The results barely change. What is the ROOT problem with your follow-ups?", options:["The AI is broken","Your follow-ups add no specific context, constraints, or direction for the AI to act on","You are using the wrong AI model","Sales emails cannot be improved by AI"], answer:1, explain:"<strong>Your follow-ups add no specific context, constraints, or direction for the AI to act on</strong>, so the model has nothing concrete to change and the output stalls.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>The AI is broken</b>: the AI behaves correctly; the issue is the vagueness of the instructions.</span><span class='qd'><b>You are using the wrong AI model</b>: switching models will not fix directionless, one-word prompts.</span><span class='qd'><b>Sales emails cannot be improved by AI</b>: sales emails improve readily with specific, detailed follow-ups.</span>" },
  { id:"D4-047", domain:4, obj:"4.3", diff:"hard", q:"An AI report is strong but omits the assumptions behind its numbers, which your finance team will demand. Which follow-up adds the RIGHT element for that audience?", options:["&quot;Make it more persuasive.&quot;","&quot;Turn it into a slideshow.&quot;","&quot;Add a clearly labeled section listing every assumption behind the financial figures.&quot;","&quot;Use a more formal font.&quot;"], answer:2, explain:"<strong>&quot;Add a clearly labeled section listing every assumption behind the financial figures.&quot;</strong> supplies exactly the missing element your finance audience needs to evaluate the numbers.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>&quot;Make it more persuasive.&quot;</b>: persuasion does not expose the underlying assumptions the audience requires.</span><span class='qd'><b>&quot;Turn it into a slideshow.&quot;</b>: changing the format does not add the assumptions themselves.</span><span class='qd'><b>&quot;Use a more formal font.&quot;</b>: font choice has no bearing on documenting financial assumptions.</span>" },
  { id:"D4-048", domain:4, obj:"4.3", diff:"medium", q:"Which of these follow-ups is LEAST likely to meaningfully improve a generic AI draft?", options:["&quot;Target this at hospital administrators, not clinicians.&quot;","&quot;Keep it under 200 words and use a formal tone.&quot;","&quot;Add a real-world example from the retail sector.&quot;","&quot;Just make it good.&quot;"], answer:3, explain:"<strong>&quot;Just make it good.&quot;</strong> gives the AI no context, constraint, or direction, so it is the weakest of the four for improving a draft.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>&quot;Target this at hospital administrators, not clinicians.&quot;</b>: this adds a clear audience, which meaningfully steers the revision.</span><span class='qd'><b>&quot;Keep it under 200 words and use a formal tone.&quot;</b>: this sets a concrete length and tone, which improves fit.</span><span class='qd'><b>&quot;Add a real-world example from the retail sector.&quot;</b>: this adds a specific element that enriches the draft.</span>" },
  { id:"D4-049", domain:4, obj:"4.3", diff:"easy", q:"Adding &quot;for an audience of busy executives who skim&quot; to a follow-up is an example of adding:", options:["Context about the audience","A grammatical error","A random constraint unrelated to the task","A request to delete the answer"], answer:0, explain:"<strong>Context about the audience</strong> tells the AI who will read the output so it can adjust length, tone, and emphasis accordingly.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>A grammatical error</b>: the phrase is meaningful guidance, not a mistake.</span><span class='qd'><b>A random constraint unrelated to the task</b>: audience information is directly relevant, not random.</span><span class='qd'><b>A request to delete the answer</b>: it asks the AI to tailor the answer, not remove it.</span>" },
  { id:"D4-050", domain:4, obj:"4.3", diff:"medium", q:"The AI keeps producing answers that are too long. Which follow-up applies the RIGHT technique to fix this?", options:["&quot;Explain your reasoning in more depth.&quot;","&quot;Limit your answer to three sentences.&quot;","&quot;Why are your answers long?&quot;","&quot;Add more supporting detail.&quot;"], answer:1, explain:"<strong>&quot;Limit your answer to three sentences.&quot;</strong> adds a length constraint that directly controls the verbosity.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>&quot;Explain your reasoning in more depth.&quot;</b>: this asks for more content, making answers longer.</span><span class='qd'><b>&quot;Why are your answers long?&quot;</b>: this clarifies but does not impose the limit you need.</span><span class='qd'><b>&quot;Add more supporting detail.&quot;</b>: adding detail increases length rather than reducing it.</span>" },
  { id:"D4-051", domain:4, obj:"4.4", diff:"easy", q:"Which follow-up asks the AI to CRITIQUE its own response?", options:["&quot;Make it longer.&quot;","&quot;Who is the audience?&quot;","&quot;Review your answer and point out any weaknesses or gaps.&quot;","&quot;Change the tone.&quot;"], answer:2, explain:"<strong>&quot;Review your answer and point out any weaknesses or gaps.&quot;</strong> directs the AI to evaluate its own work, which is a self-critique.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>&quot;Make it longer.&quot;</b>: this expands the output rather than evaluating it.</span><span class='qd'><b>&quot;Who is the audience?&quot;</b>: this is a clarifying question, not a request for self-review.</span><span class='qd'><b>&quot;Change the tone.&quot;</b>: this is a style change and does not ask the AI to assess its answer.</span>" },
  { id:"D4-052", domain:4, obj:"4.4", diff:"easy", q:"What is the purpose of asking an AI to &quot;check your work and fix any mistakes&quot;?", options:["To make the AI apologize","To change the language of the response","To end the conversation","To prompt the AI to review its output and improve accuracy or quality"], answer:3, explain:"<strong>To prompt the AI to review its output and improve accuracy or quality</strong> is the goal of a self-check follow-up, which often catches issues in the first draft.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>To make the AI apologize</b>: the aim is improvement, not an apology.</span><span class='qd'><b>To end the conversation</b>: asking for a review continues the conversation rather than ending it.</span><span class='qd'><b>To change the language of the response</b>: a self-check is about quality, not translation.</span>" },
  { id:"D4-053", domain:4, obj:"4.4", diff:"easy", q:"Asking the AI &quot;Are there any counterarguments to your recommendation?&quot; is a form of:", options:["Self-critique that surfaces weaknesses","Formatting change","Clarifying a term","Ending the thread"], answer:0, explain:"<strong>Self-critique that surfaces weaknesses</strong> is exactly what asking for counterarguments does, pushing the AI to challenge its own answer.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Formatting change</b>: requesting counterarguments does not alter the output's format.</span><span class='qd'><b>Clarifying a term</b>: it asks for opposing views, not a definition.</span><span class='qd'><b>Ending the thread</b>: it deepens the discussion rather than closing it.</span>" },
  { id:"D4-054", domain:4, obj:"4.4", diff:"easy", q:"After the AI critiques its own answer and finds a flaw, what is the natural NEXT step?", options:["Ignore the flaw it found","Ask the AI to revise the answer to fix the flaw","Start an unrelated chat","Ask it to critique a different topic"], answer:1, explain:"<strong>Ask the AI to revise the answer to fix the flaw</strong> turns the self-critique into an actual improvement.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Ignore the flaw it found</b>: ignoring the identified flaw wastes the value of the critique.</span><span class='qd'><b>Start an unrelated chat</b>: switching topics leaves the flaw unfixed.</span><span class='qd'><b>Ask it to critique a different topic</b>: critiquing something else does not repair the current answer.</span>" },
  { id:"D4-055", domain:4, obj:"4.4", diff:"medium", q:"You are unsure whether an AI-written plan has hidden weaknesses. Which follow-up BEST uses the self-critique technique?", options:["&quot;Rewrite it in a friendlier tone.&quot;","&quot;Make it two pages long.&quot;","&quot;Act as a skeptical reviewer and list the three biggest risks in this plan, then suggest fixes.&quot;","&quot;What is a plan?&quot;"], answer:2, explain:"<strong>&quot;Act as a skeptical reviewer and list the three biggest risks in this plan, then suggest fixes.&quot;</strong> makes the AI critique its own work and propose improvements.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>&quot;Rewrite it in a friendlier tone.&quot;</b>: tone changes do not reveal hidden weaknesses.</span><span class='qd'><b>&quot;Make it two pages long.&quot;</b>: length has nothing to do with surfacing risks.</span><span class='qd'><b>&quot;What is a plan?&quot;</b>: a definitional question does not evaluate the plan you have.</span>" },
  { id:"D4-056", domain:4, obj:"4.4", diff:"medium", q:"Why can asking the AI to critique its own answer be a useful quality step, even though you should still verify important facts yourself?", options:["It replaces the need to verify anything","It makes the AI legally responsible for the content","It guarantees zero errors","It can catch obvious gaps, inconsistencies, or missing considerations before you review"], answer:3, explain:"<strong>It can catch obvious gaps, inconsistencies, or missing considerations before you review</strong>, which improves the draft even though your own verification is still needed.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>It replaces the need to verify anything</b>: self-critique supplements verification but never replaces it.</span><span class='qd'><b>It guarantees zero errors</b>: no prompt guarantees an error-free answer.</span><span class='qd'><b>It makes the AI legally responsible for the content</b>: responsibility for using the content stays with you, not the tool.</span>" },
  { id:"D4-057", domain:4, obj:"4.4", diff:"medium", q:"An AI gave you an answer that sounds confident. You worry it might be overstating certainty. Which follow-up BEST tests this?", options:["&quot;How confident are you in this, and which parts are you least sure about?&quot;","&quot;Make it sound even more confident.&quot;","&quot;Add more adjectives.&quot;","&quot;Change the topic.&quot;"], answer:0, explain:"<strong>&quot;How confident are you in this, and which parts are you least sure about?&quot;</strong> prompts the AI to critique its own certainty and flag weak spots.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>&quot;Make it sound even more confident.&quot;</b>: boosting confidence hides the uncertainty you want to expose.</span><span class='qd'><b>&quot;Add more adjectives.&quot;</b>: adjectives do not test how reliable the claims are.</span><span class='qd'><b>&quot;Change the topic.&quot;</b>: switching topics abandons your concern about overconfidence.</span>" },
  { id:"D4-058", domain:4, obj:"4.4", diff:"medium", q:"Which follow-up asks the AI to evaluate its answer AND then act on that evaluation?", options:["&quot;Make it prettier.&quot;","&quot;Critique this answer, then rewrite it to address the problems you found.&quot;","&quot;What is the weather?&quot;","&quot;Translate it to Spanish.&quot;"], answer:1, explain:"<strong>&quot;Critique this answer, then rewrite it to address the problems you found.&quot;</strong> asks for both self-evaluation and a corrected revision in one step.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>&quot;Make it prettier.&quot;</b>: this is a vague style request with no evaluation.</span><span class='qd'><b>&quot;What is the weather?&quot;</b>: this is unrelated to reviewing the answer.</span><span class='qd'><b>&quot;Translate it to Spanish.&quot;</b>: translation neither critiques nor improves the substance.</span>" },
  { id:"D4-059", domain:4, obj:"4.4", diff:"hard", q:"You want an AI proposal to withstand tough questions from executives. Which self-critique follow-up is MOST effective before the meeting?", options:["&quot;Summarize the proposal in one line.&quot;","&quot;Make the proposal longer.&quot;","&quot;Play a tough executive: ask the five hardest questions about this proposal and answer each.&quot;","&quot;Change the headings.&quot;"], answer:2, explain:"<strong>&quot;Play a tough executive: ask the five hardest questions about this proposal and answer each.&quot;</strong> forces the AI to stress-test its own work from a skeptical viewpoint.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>&quot;Summarize the proposal in one line.&quot;</b>: a one-line summary does not probe for weaknesses.</span><span class='qd'><b>&quot;Make the proposal longer.&quot;</b>: length alone does not prepare the proposal for tough questions.</span><span class='qd'><b>&quot;Change the headings.&quot;</b>: reformatting headings does nothing to test the argument's strength.</span>" },
  { id:"D4-060", domain:4, obj:"4.4", diff:"hard", q:"An AI-generated analysis relies on several claims. You suspect one is a hallucination. Which combination of moves is BEST?", options:["Trust the AI's self-check and skip verifying","Delete the analysis and start over blindly","Ask the AI to make the claims stronger","Ask the AI to flag any claim it cannot support, then independently verify those flagged claims"], answer:3, explain:"<strong>Ask the AI to flag any claim it cannot support, then independently verify those flagged claims</strong> pairs self-critique with human verification, which is the responsible way to handle possible hallucinations.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Trust the AI's self-check and skip verifying</b>: a self-check can miss its own errors, so skipping verification is risky.</span><span class='qd'><b>Ask the AI to make the claims stronger</b>: strengthening unverified claims makes a possible hallucination sound more convincing, not more accurate.</span><span class='qd'><b>Delete the analysis and start over blindly</b>: discarding usable work without checking is wasteful and does not address why the claim seemed off.</span>" },
  { id:"D4-061", domain:4, obj:"4.4", diff:"hard", q:"After the AI critiques its own draft, it insists nothing is wrong, yet you can see a clear factual error. What is the BEST next move?", options:["Point out the specific error and ask the AI to correct it","Accept the AI's assurance that it is correct","Ask the AI to critique a different document","Assume the error is fine because the AI is confident"], answer:0, explain:"<strong>Point out the specific error and ask the AI to correct it</strong> supplies the concrete correction the AI missed, keeping you in control of accuracy.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Accept the AI's assurance that it is correct</b>: the AI's confidence does not override a clear error you can see.</span><span class='qd'><b>Ask the AI to critique a different document</b>: critiquing something else leaves the visible error unfixed.</span><span class='qd'><b>Assume the error is fine because the AI is confident</b>: confidence is not accuracy, so assuming it is fine can pass along a mistake.</span>" },
  { id:"D4-062", domain:4, obj:"4.4", diff:"medium", q:"Which of these is NOT a self-critique follow-up?", options:["&quot;List any assumptions you made that could be wrong.&quot;","&quot;Rewrite this in bold, large font.&quot;","&quot;Identify the weakest part of your argument.&quot;","&quot;Double-check the numbers for accuracy.&quot;"], answer:1, explain:"<strong>&quot;Rewrite this in bold, large font.&quot;</strong> is a formatting change and does not ask the AI to evaluate the quality of its answer.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>&quot;List any assumptions you made that could be wrong.&quot;</b>: this asks the AI to examine its own reasoning, which is self-critique.</span><span class='qd'><b>&quot;Identify the weakest part of your argument.&quot;</b>: this directs the AI to find flaws in its own work.</span><span class='qd'><b>&quot;Double-check the numbers for accuracy.&quot;</b>: this asks the AI to verify its output, a self-check.</span>" },
  { id:"D4-063", domain:4, obj:"4.4", diff:"medium", q:"You want a balanced answer but the AI only argued one side. Which self-critique-style follow-up BEST balances it?", options:["&quot;Add more detail to your side.&quot;","&quot;Make it more persuasive for your side.&quot;","&quot;Now argue the opposing view and note where your original answer was one-sided.&quot;","&quot;Shorten the answer.&quot;"], answer:2, explain:"<strong>&quot;Now argue the opposing view and note where your original answer was one-sided.&quot;</strong> makes the AI critique its own bias and supply the missing perspective.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>&quot;Add more detail to your side.&quot;</b>: this deepens the bias instead of balancing it.</span><span class='qd'><b>&quot;Make it more persuasive for your side.&quot;</b>: stronger one-sided arguing worsens the imbalance.</span><span class='qd'><b>&quot;Shorten the answer.&quot;</b>: length does not address the missing opposing view.</span>" },
  { id:"D4-064", domain:4, obj:"4.4", diff:"easy", q:"Asking the AI &quot;Did you miss anything important?&quot; is intended to:", options:["Change the formatting","Translate the answer","End the session","Prompt the AI to review its answer for gaps"], answer:3, explain:"<strong>Prompt the AI to review its answer for gaps</strong> is the purpose of asking whether it missed anything, encouraging a more complete response.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Change the formatting</b>: the question concerns completeness, not layout.</span><span class='qd'><b>End the session</b>: it invites a fuller answer rather than ending the chat.</span><span class='qd'><b>Translate the answer</b>: it asks about omissions, not language.</span>" },
  { id:"D4-065", domain:4, obj:"4.4", diff:"medium", q:"Which follow-up would BEST help an AI catch its own logical inconsistencies?", options:["&quot;Reread your answer and point out any places where two statements conflict.&quot;","&quot;Add a friendly greeting.&quot;","&quot;Make it rhyme.&quot;","&quot;Use a bigger vocabulary.&quot;"], answer:0, explain:"<strong>&quot;Reread your answer and point out any places where two statements conflict.&quot;</strong> directs the AI to hunt for internal contradictions, a targeted self-critique.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>&quot;Add a friendly greeting.&quot;</b>: a greeting does nothing to detect inconsistencies.</span><span class='qd'><b>&quot;Make it rhyme.&quot;</b>: rhyming is a style change unrelated to logic.</span><span class='qd'><b>&quot;Use a bigger vocabulary.&quot;</b>: fancier words do not surface conflicting statements.</span>" },
  { id:"D4-066", domain:4, obj:"4.5", diff:"easy", q:"What is prompt chaining?", options:["Sending one giant prompt that does everything at once","Breaking a task into steps where each prompt builds on the previous output","Locking the AI so it cannot respond","Using the same prompt repeatedly"], answer:1, explain:"<strong>Breaking a task into steps where each prompt builds on the previous output</strong> defines prompt chaining, which handles complex tasks in manageable pieces.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Sending one giant prompt that does everything at once</b>: that is the opposite of chaining, which deliberately splits the work.</span><span class='qd'><b>Locking the AI so it cannot respond</b>: chaining is about sequencing prompts, not disabling the AI.</span><span class='qd'><b>Using the same prompt repeatedly</b>: repetition is not chaining because nothing builds on the prior result.</span>" },
  { id:"D4-067", domain:4, obj:"4.5", diff:"easy", q:"Which sequence is an example of prompt chaining?", options:["Ask four unrelated questions in four separate chats","Ask the same question three times","Ask for a topic list, then ask the AI to draft an article from a chosen topic, then ask it to write a headline for that draft","Ask nothing and wait"], answer:2, explain:"<strong>Ask for a topic list, then ask the AI to draft an article from a chosen topic, then ask it to write a headline for that draft</strong> shows each step feeding the next, which is prompt chaining.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Ask the same question three times</b>: repeating a question does not build a chain of dependent steps.</span><span class='qd'><b>Ask four unrelated questions in four separate chats</b>: unrelated questions in separate chats share no output to build on.</span><span class='qd'><b>Ask nothing and wait</b>: doing nothing produces no chain at all.</span>" },
  { id:"D4-068", domain:4, obj:"4.5", diff:"easy", q:"In prompt chaining, the output of one step is typically used as:", options:["An unrelated tangent","A reason to end the conversation","A file to delete","The input or foundation for the next step"], answer:3, explain:"<strong>The input or foundation for the next step</strong> is how chaining works, with each result feeding the following prompt.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>A reason to end the conversation</b>: chaining continues the work rather than ending it.</span><span class='qd'><b>A file to delete</b>: outputs are reused, not discarded, in a chain.</span><span class='qd'><b>An unrelated tangent</b>: chained steps stay connected to the task, not off-topic.</span>" },
  { id:"D4-069", domain:4, obj:"4.5", diff:"easy", q:"Why is prompt chaining helpful for a big, multi-part task?", options:["It lets you tackle the task step by step, checking and steering each stage","It forces the AI to answer everything in one confusing response","It prevents the AI from remembering anything","It removes the need to give any instructions"], answer:0, explain:"<strong>It lets you tackle the task step by step, checking and steering each stage</strong>, which improves quality and control on complex work.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>It forces the AI to answer everything in one confusing response</b>: chaining avoids one giant response by splitting the task.</span><span class='qd'><b>It prevents the AI from remembering anything</b>: chaining relies on the AI carrying prior outputs forward, not forgetting them.</span><span class='qd'><b>It removes the need to give any instructions</b>: each step still needs clear instructions.</span>" },
  { id:"D4-070", domain:4, obj:"4.5", diff:"medium", q:"You want to turn raw meeting notes into a polished summary email. Which chained approach is BEST?", options:["Ask for the final email in one prompt with no intermediate steps","First have the AI extract key decisions and action items, then have it draft the email from those extracted points","Paste the notes and ask &quot;make it good&quot;","Ask for the email in a brand-new chat with none of the notes"], answer:1, explain:"<strong>First have the AI extract key decisions and action items, then have it draft the email from those extracted points</strong> chains a structured intermediate result into a stronger final email.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Ask for the final email in one prompt with no intermediate steps</b>: skipping the extraction step can bury or miss key items in a single pass.</span><span class='qd'><b>Paste the notes and ask &quot;make it good&quot;</b>: this vague request gives no structure for the AI to organize the notes.</span><span class='qd'><b>Ask for the email in a brand-new chat with none of the notes</b>: without the notes as context, the AI cannot summarize them.</span>" },
  { id:"D4-071", domain:4, obj:"4.5", diff:"medium", q:"During a chained workflow, the AI's step-2 draft is based on a step-1 outline you actually disliked. What should you do BEFORE continuing the chain?", options:["Keep chaining and hope it improves later","Ignore the outline entirely","Fix or replace the step-1 outline first, since later steps build on it","Start a new chat with no outline"], answer:2, explain:"<strong>Fix or replace the step-1 outline first, since later steps build on it</strong> prevents a flawed foundation from propagating through the rest of the chain.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Keep chaining and hope it improves later</b>: building on a bad outline usually carries its problems into every later step.</span><span class='qd'><b>Ignore the outline entirely</b>: the outline is the foundation, so ignoring it does not remove its influence on step 2.</span><span class='qd'><b>Start a new chat with no outline</b>: discarding the whole thread loses the good work and the shared context.</span>" },
  { id:"D4-072", domain:4, obj:"4.5", diff:"medium", q:"Which situation BEST calls for prompt chaining rather than a single prompt?", options:["Asking for the definition of one word","Requesting a single synonym","Asking what time zone a city is in","Producing a market analysis that requires gathering data, then analyzing it, then writing recommendations"], answer:3, explain:"<strong>Producing a market analysis that requires gathering data, then analyzing it, then writing recommendations</strong> is a multi-stage task where chaining lets you verify each stage.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Asking for the definition of one word</b>: a single simple question needs no chain.</span><span class='qd'><b>Asking what time zone a city is in</b>: this is a one-shot factual lookup, not a multi-step task.</span><span class='qd'><b>Requesting a single synonym</b>: one synonym is a trivial single prompt with nothing to chain.</span>" },
  { id:"D4-073", domain:4, obj:"4.5", diff:"medium", q:"You are chaining prompts to write a report, and you want continuity so later steps remember earlier decisions. What practice BEST supports this?", options:["Keeping the whole chain in one thread so each step can see prior results","Doing each step in a separate chat","Deleting each result after generating it","Changing the topic between steps"], answer:0, explain:"<strong>Keeping the whole chain in one thread so each step can see prior results</strong> maintains the continuity that lets later steps build on earlier decisions.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Doing each step in a separate chat</b>: separate chats break continuity because they cannot see prior steps.</span><span class='qd'><b>Deleting each result after generating it</b>: deleting results removes the foundation the next step needs.</span><span class='qd'><b>Changing the topic between steps</b>: topic switching disrupts the coherent chain you are building.</span>" },
  { id:"D4-074", domain:4, obj:"4.5", diff:"hard", q:"You must produce a translated, localized product brochure. Which chained sequence is MOST likely to yield a high-quality result?", options:["Ask the AI to translate and localize everything in one prompt with no review","Draft the brochure, then translate it, then ask the AI to adapt cultural references for the target market, reviewing each step","Translate first with no source brochure","Ask for a brochure in a language you did not specify"], answer:1, explain:"<strong>Draft the brochure, then translate it, then ask the AI to adapt cultural references for the target market, reviewing each step</strong> chains distinct tasks and lets you check each stage for quality.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Ask the AI to translate and localize everything in one prompt with no review</b>: combining several complex tasks in one pass makes errors harder to catch.</span><span class='qd'><b>Translate first with no source brochure</b>: there is nothing to translate without the drafted brochure.</span><span class='qd'><b>Ask for a brochure in a language you did not specify</b>: an unspecified language leaves the output to chance.</span>" },
  { id:"D4-075", domain:4, obj:"4.5", diff:"hard", q:"A colleague chains ten prompts but never reviews any intermediate output, only the final one. Why is this RISKY?", options:["It is not risky; only the final output matters","The AI cannot chain more than three prompts","An error introduced in an early step can silently propagate and compound through every later step","Chaining always fixes its own mistakes"], answer:2, explain:"<strong>An error introduced in an early step can silently propagate and compound through every later step</strong>, which is why reviewing intermediate outputs matters in a chain.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>It is not risky; only the final output matters</b>: the final output inherits any early-step errors, so intermediate quality does matter.</span><span class='qd'><b>The AI cannot chain more than three prompts</b>: there is no such fixed limit; the issue is unreviewed errors.</span><span class='qd'><b>Chaining always fixes its own mistakes</b>: chaining does not self-correct; it can carry mistakes forward.</span>" },
  { id:"D4-076", domain:4, obj:"4.5", diff:"hard", q:"You are building a long analytical piece through chaining. Midway, you notice the AI has drifted from the audience you set at the start. What is the BEST way to restore continuity?", options:["Ignore the drift and keep going","Switch to a completely different task","Start a brand-new chat and lose all prior steps","Remind the AI of the original audience and constraints, then have it realign the current and subsequent steps"], answer:3, explain:"<strong>Remind the AI of the original audience and constraints, then have it realign the current and subsequent steps</strong> re-anchors the chain without discarding your progress.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Ignore the drift and keep going</b>: unchecked drift produces content aimed at the wrong readers.</span><span class='qd'><b>Start a brand-new chat and lose all prior steps</b>: abandoning the thread throws away the completed steps you can still salvage.</span><span class='qd'><b>Switch to a completely different task</b>: changing tasks does not fix the audience drift in this one.</span>" },
  { id:"D4-077", domain:4, obj:"4.5", diff:"medium", q:"Which statement about prompt chaining and continuity is TRUE?", options:["Staying in one thread lets each chained step reference the results and decisions of prior steps","Continuity is easiest when each step is in a different chat","Chaining requires you to forget earlier steps","Continuity means using a new AI tool for every step"], answer:0, explain:"<strong>Staying in one thread lets each chained step reference the results and decisions of prior steps</strong>, which is how continuity supports chaining.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Continuity is easiest when each step is in a different chat</b>: separate chats break the shared context continuity depends on.</span><span class='qd'><b>Chaining requires you to forget earlier steps</b>: chaining relies on remembering earlier steps, not forgetting them.</span><span class='qd'><b>Continuity means using a new AI tool for every step</b>: switching tools each step destroys continuity.</span>" },
  { id:"D4-078", domain:4, obj:"4.5", diff:"medium", q:"You want to generate code, then have the AI explain it, then have it write tests. Ordering these as three connected prompts is an example of:", options:["A single one-shot request","Prompt chaining that builds each step on the last","A hard reset between steps","Ignoring prior outputs"], answer:1, explain:"<strong>Prompt chaining that builds each step on the last</strong> describes generating code, explaining it, then testing it in a connected sequence.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>A single one-shot request</b>: three connected prompts are not a single shot.</span><span class='qd'><b>A hard reset between steps</b>: a reset would erase the code the later steps depend on.</span><span class='qd'><b>Ignoring prior outputs</b>: the explanation and tests depend on the earlier code, so prior outputs are used, not ignored.</span>" },
  { id:"D4-079", domain:4, obj:"4.5", diff:"hard", q:"In a chained workflow, when is it appropriate to STOP chaining in the current thread and start fresh?", options:["Never; you must always continue the same thread","After exactly five prompts, always","When the thread has become cluttered or the AI is losing track, and a clean summary can seed a new thread","Whenever the AI gives a correct answer"], answer:2, explain:"<strong>When the thread has become cluttered or the AI is losing track, and a clean summary can seed a new thread</strong> balances continuity against the cost of an overloaded thread.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Never; you must always continue the same thread</b>: sometimes a fresh, summarized thread outperforms a confused one.</span><span class='qd'><b>After exactly five prompts, always</b>: there is no fixed prompt count that dictates starting over.</span><span class='qd'><b>Whenever the AI gives a correct answer</b>: a correct answer is a reason to proceed, not to reset.</span>" },
  { id:"D4-080", domain:4, obj:"4.5", diff:"medium", q:"What is a practical benefit of reviewing the output at EACH link of a prompt chain?", options:["It slows you down for no reason","It hides the intermediate results","It forces the AI to start over each time","It lets you catch and fix problems early before they affect later steps"], answer:3, explain:"<strong>It lets you catch and fix problems early before they affect later steps</strong>, keeping the whole chain on track.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>It slows you down for no reason</b>: the review has a clear reason, preventing compounding errors.</span><span class='qd'><b>It forces the AI to start over each time</b>: reviewing does not restart the chain; it verifies each step.</span><span class='qd'><b>It hides the intermediate results</b>: reviewing exposes intermediate results rather than hiding them.</span>" },
  { id:"D4-081", domain:4, obj:"4.1", diff:"medium", q:"Which of the following BEST demonstrates using AI as a thinking partner across several turns rather than a one-shot tool?", options:["Discussing an idea with the AI, challenging its points, and refining a plan together over several messages","Pasting a question and copying the first answer into your document","Asking one question and closing the app","Requesting a single fact and stopping"], answer:0, explain:"<strong>Discussing an idea with the AI, challenging its points, and refining a plan together over several messages</strong> treats the AI as an iterative partner, the core of Domain 4.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Pasting a question and copying the first answer into your document</b>: taking the first answer without discussion is a one-shot transaction.</span><span class='qd'><b>Asking one question and closing the app</b>: a single exchange is not a multi-turn partnership.</span><span class='qd'><b>Requesting a single fact and stopping</b>: a lone fact lookup involves no back-and-forth refinement.</span>" },
  { id:"D4-082", domain:4, obj:"4.2", diff:"hard", q:"An AI answer uses the word &quot;stakeholders&quot; in a way that seems broader than you expected. Before you rewrite your project plan around it, the BEST move is to:", options:["Rewrite the plan immediately using your own guess of the meaning","Ask the AI who it considers the stakeholders in this context, then confirm that matches your reality","Remove the word from the plan","Ask the AI to use fancier terminology"], answer:1, explain:"<strong>Ask the AI who it considers the stakeholders in this context, then confirm that matches your reality</strong> clarifies the term's scope before you build important work on it.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Rewrite the plan immediately using your own guess of the meaning</b>: guessing risks planning around the wrong set of people.</span><span class='qd'><b>Remove the word from the plan</b>: removing a key term avoids clarification instead of resolving the ambiguity.</span><span class='qd'><b>Ask the AI to use fancier terminology</b>: more elaborate wording does not clarify who the stakeholders actually are.</span>" },
  { id:"D4-083", domain:4, obj:"4.3", diff:"hard", q:"You have iterated four times and the AI's tone is now perfect, but it dropped a key legal disclaimer you needed. Which follow-up BEST fixes this without losing the good tone?", options:["&quot;Start completely over.&quot;","&quot;Change the tone again.&quot;","&quot;Keep the current tone exactly, but add back the required legal disclaimer at the end.&quot;","&quot;Make it much shorter.&quot;"], answer:2, explain:"<strong>&quot;Keep the current tone exactly, but add back the required legal disclaimer at the end.&quot;</strong> preserves what you like while restoring the missing element.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>&quot;Start completely over.&quot;</b>: starting over risks losing the tone you spent four turns perfecting.</span><span class='qd'><b>&quot;Change the tone again.&quot;</b>: another tone change threatens the tone you already got right and ignores the disclaimer.</span><span class='qd'><b>&quot;Make it much shorter.&quot;</b>: shortening could cut more content and does not add the disclaimer.</span>" },
  { id:"D4-084", domain:4, obj:"4.4", diff:"medium", q:"Which follow-up BEST combines a self-critique with a request to improve, in one efficient message?", options:["&quot;Make it longer and add emojis.&quot;","&quot;What is the capital of France?&quot;","&quot;Translate this to German.&quot;","&quot;Identify the two weakest arguments here and rewrite them to be stronger and better supported.&quot;"], answer:3, explain:"<strong>&quot;Identify the two weakest arguments here and rewrite them to be stronger and better supported.&quot;</strong> asks the AI to critique and then act on the critique in a single step.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>&quot;Make it longer and add emojis.&quot;</b>: this changes length and style without any evaluation.</span><span class='qd'><b>&quot;Translate this to German.&quot;</b>: translation neither critiques nor strengthens the arguments.</span><span class='qd'><b>&quot;What is the capital of France?&quot;</b>: this is unrelated to reviewing or improving the answer.</span>" },
  { id:"D4-085", domain:4, obj:"4.5", diff:"medium", q:"You chained three prompts to plan an event, and the final checklist is good but you now want a budget based on it. What is the BEST continuation?", options:["In the same thread, ask the AI to build a budget from the checklist it just produced","Open a new chat and describe the event from memory","Ask for a budget with no reference to the checklist","Repeat the checklist prompt again"], answer:0, explain:"<strong>In the same thread, ask the AI to build a budget from the checklist it just produced</strong> extends the chain, using the existing checklist as the foundation for the budget.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Open a new chat and describe the event from memory</b>: a new chat forces you to re-supply context the current thread already holds.</span><span class='qd'><b>Ask for a budget with no reference to the checklist</b>: ignoring the checklist wastes the structured work you already have.</span><span class='qd'><b>Repeat the checklist prompt again</b>: regenerating the checklist does not move you toward the budget.</span>" },
  { id:"D4-086", domain:4, obj:"4.1", diff:"medium", q:"A user complains that the AI &quot;never gets it right the first time.&quot; What is the MOST accurate reframing of this complaint?", options:["The AI is defective and should be replaced","First answers are drafts, and a follow-up or two is a normal, expected part of getting a great result","AI can only be used for trivial tasks","You should never expect useful output from AI"], answer:1, explain:"<strong>First answers are drafts, and a follow-up or two is a normal, expected part of getting a great result</strong> reframes iteration as the process working as intended.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>The AI is defective and should be replaced</b>: needing follow-ups is expected behavior, not a defect.</span><span class='qd'><b>AI can only be used for trivial tasks</b>: AI handles complex tasks well precisely because you can iterate.</span><span class='qd'><b>You should never expect useful output from AI</b>: useful output is common, especially after refinement.</span>" },
  { id:"D4-087", domain:4, obj:"4.2", diff:"medium", q:"Which of the following is the BEST reason to ask a clarifying question EARLY in a conversation rather than late?", options:["It makes the chat look longer","It forces the AI to reset","It prevents a misunderstanding from shaping all the work that follows","It changes the AI's font"], answer:2, explain:"<strong>It prevents a misunderstanding from shaping all the work that follows</strong>, so catching confusion early saves rework across the whole conversation.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>It makes the chat look longer</b>: length is not the point; correctness of understanding is.</span><span class='qd'><b>It forces the AI to reset</b>: a clarifying question does not reset the AI.</span><span class='qd'><b>It changes the AI's font</b>: clarifying meaning has nothing to do with formatting.</span>" },
  { id:"D4-088", domain:4, obj:"4.3", diff:"medium", q:"You keep getting American spelling but your audience is British. Which follow-up adds the RIGHT constraint?", options:["&quot;Make it more formal.&quot;","&quot;Why is the spelling American?&quot;","&quot;Add more examples.&quot;","&quot;Use British English spelling and conventions throughout.&quot;"], answer:3, explain:"<strong>&quot;Use British English spelling and conventions throughout.&quot;</strong> sets a precise constraint that fixes the spelling for your audience.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>&quot;Make it more formal.&quot;</b>: formality does not control which spelling convention is used.</span><span class='qd'><b>&quot;Add more examples.&quot;</b>: examples do not address the spelling mismatch.</span><span class='qd'><b>&quot;Why is the spelling American?&quot;</b>: this clarifies but does not instruct the switch to British spelling.</span>" },
  { id:"D4-089", domain:4, obj:"4.4", diff:"hard", q:"You want to reduce the chance that an AI-written FAQ contains subtle inaccuracies. Which self-critique step is MOST valuable, understanding you will still fact-check?", options:["&quot;Review each answer and mark any statement that may not be accurate or that you are uncertain about.&quot;","&quot;Add more questions to the FAQ.&quot;","&quot;Make the FAQ more colorful.&quot;","&quot;Shorten the answers.&quot;"], answer:0, explain:"<strong>&quot;Review each answer and mark any statement that may not be accurate or that you are uncertain about.&quot;</strong> surfaces the risky claims so your fact-check can focus on them.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>&quot;Add more questions to the FAQ.&quot;</b>: adding questions increases the volume to verify without flagging risks.</span><span class='qd'><b>&quot;Make the FAQ more colorful.&quot;</b>: styling does not identify potential inaccuracies.</span><span class='qd'><b>&quot;Shorten the answers.&quot;</b>: shortening does not reveal which statements might be wrong.</span>" },
  { id:"D4-090", domain:4, obj:"4.5", diff:"hard", q:"A complex research task keeps failing when asked all at once. You decide to chain it. Which FIRST step best sets up a reliable chain?", options:["Ask for the final conclusion immediately","Ask the AI to lay out the sub-steps needed to complete the task, then work through them one at a time","Ask an unrelated question to warm up","Ask for the answer in a different language"], answer:1, explain:"<strong>Ask the AI to lay out the sub-steps needed to complete the task, then work through them one at a time</strong> creates a clear plan you can chain through reliably.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Ask for the final conclusion immediately</b>: jumping to the conclusion is the all-at-once approach that already failed.</span><span class='qd'><b>Ask an unrelated question to warm up</b>: an unrelated question adds no structure to the task.</span><span class='qd'><b>Ask for the answer in a different language</b>: changing language does not help break the task into steps.</span>" },
  { id:"D4-091", domain:4, obj:"4.1", diff:"hard", q:"You are collaborating with the AI over many turns on a strategy document. Which habit MOST improves the final quality across the whole conversation?", options:["Accepting each answer without reading it","Sending only one-word replies","Reviewing each response, then steering the next turn with specific, purposeful follow-ups","Switching to a new chat after every message"], answer:2, explain:"<strong>Reviewing each response, then steering the next turn with specific, purposeful follow-ups</strong> is the disciplined iteration that lifts quality throughout a long collaboration.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Accepting each answer without reading it</b>: unreviewed answers cannot be steered or corrected.</span><span class='qd'><b>Sending only one-word replies</b>: vague one-word replies give the AI little direction.</span><span class='qd'><b>Switching to a new chat after every message</b>: constant new chats destroy the continuity a strategy document needs.</span>" },
  { id:"D4-092", domain:4, obj:"4.2", diff:"easy", q:"If the AI uses an abbreviation you have never seen, the FIRST thing you should consider doing is:", options:["Guess what it means and keep going","Ignore that entire sentence","End the chat in frustration","Ask the AI to spell out and explain the abbreviation"], answer:3, explain:"<strong>Ask the AI to spell out and explain the abbreviation</strong> clears up the unfamiliar term before you continue building on the answer.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Guess what it means and keep going</b>: guessing risks proceeding on a wrong understanding.</span><span class='qd'><b>End the chat in frustration</b>: quitting abandons the task over a quick, answerable question.</span><span class='qd'><b>Ignore that entire sentence</b>: ignoring it may skip something important you needed to grasp.</span>" },
  { id:"D4-093", domain:4, obj:"4.3", diff:"easy", q:"Which follow-up is the STRONGEST example of tightening a request with a specific constraint?", options:["&quot;Rewrite this as exactly three sentences aimed at new customers.&quot;","&quot;Improve it.&quot;","&quot;Make it nice.&quot;","&quot;Do your best.&quot;"], answer:0, explain:"<strong>&quot;Rewrite this as exactly three sentences aimed at new customers.&quot;</strong> pins down both a length constraint and an audience, giving the AI clear direction.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>&quot;Improve it.&quot;</b>: this specifies no constraint and leaves the result to chance.</span><span class='qd'><b>&quot;Make it nice.&quot;</b>: &quot;nice&quot; is subjective and imposes no measurable boundary.</span><span class='qd'><b>&quot;Do your best.&quot;</b>: this adds no constraint or target at all.</span>" },
  { id:"D4-094", domain:4, obj:"4.4", diff:"medium", q:"Which follow-up would BEST prompt the AI to check whether its answer actually addressed your original question?", options:["&quot;Add a summary sentence.&quot;","&quot;Compare your answer to my original request and tell me if anything I asked for is missing.&quot;","&quot;Make it bold.&quot;","&quot;Translate it.&quot;"], answer:1, explain:"<strong>&quot;Compare your answer to my original request and tell me if anything I asked for is missing.&quot;</strong> makes the AI audit its own response against your requirements.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>&quot;Add a summary sentence.&quot;</b>: a summary does not verify completeness against your request.</span><span class='qd'><b>&quot;Make it bold.&quot;</b>: styling does not check whether the question was answered.</span><span class='qd'><b>&quot;Translate it.&quot;</b>: translation does not evaluate coverage of your ask.</span>" },
  { id:"D4-095", domain:4, obj:"4.5", diff:"medium", q:"Which describes a well-run chained conversation?", options:["Each prompt is unrelated to the last and context is discarded","Every step happens in a separate app with no memory","Each prompt builds on a reviewed prior output, and the thread preserves continuity","The user never checks any intermediate result"], answer:2, explain:"<strong>Each prompt builds on a reviewed prior output, and the thread preserves continuity</strong> captures disciplined chaining that produces reliable results.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Each prompt is unrelated to the last and context is discarded</b>: discarding context breaks the chain.</span><span class='qd'><b>Every step happens in a separate app with no memory</b>: separate apps with no memory cannot maintain continuity.</span><span class='qd'><b>The user never checks any intermediate result</b>: skipping review lets early errors compound.</span>" },
  { id:"D4-096", domain:4, obj:"4.1", diff:"hard", q:"You gave the AI a great deal of context in turn 1, then in turn 8 you paste a totally unrelated new task into the same thread. What is the likely DOWNSIDE?", options:["The AI will refuse to answer the new task","The AI will become permanently confused for all users","The thread will delete itself","The old context may bleed into the new task and skew the response"], answer:3, explain:"<strong>The old context may bleed into the new task and skew the response</strong>, which is why an unrelated task usually belongs in a fresh thread.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>The AI will refuse to answer the new task</b>: it will attempt the task, but possibly colored by stale context.</span><span class='qd'><b>The thread will delete itself</b>: adding a new task does not delete the thread.</span><span class='qd'><b>The AI will become permanently confused for all users</b>: any confusion is local to this thread, not global.</span>" },
  { id:"D4-097", domain:4, obj:"4.2", diff:"hard", q:"An AI answer hinges on a single technical assumption you do not fully understand and cannot yet evaluate. Before acting, the BEST clarifying step is to:", options:["Ask the AI to state the assumption plainly and explain what happens if it is false","Act now and hope the assumption holds","Rewrite the answer to remove all technical content","Ask the AI to add more technical assumptions"], answer:0, explain:"<strong>Ask the AI to state the assumption plainly and explain what happens if it is false</strong> clarifies the load-bearing assumption and its risk before you rely on the answer.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Act now and hope the assumption holds</b>: acting on an assumption you do not understand is the exact risk to avoid.</span><span class='qd'><b>Rewrite the answer to remove all technical content</b>: stripping the technical content may remove the very basis of the answer.</span><span class='qd'><b>Ask the AI to add more technical assumptions</b>: piling on assumptions deepens the uncertainty rather than clarifying it.</span>" },
  { id:"D4-098", domain:4, obj:"4.3", diff:"hard", q:"You have combined several techniques: you clarified a term, added audience context, and set a length limit. The result is strong but slightly too formal. What is the MOST efficient single follow-up now?", options:["&quot;Redo everything from scratch.&quot;","&quot;Keep the length and audience the same, but make the tone a bit more casual.&quot;","&quot;Change the audience and the length too.&quot;","&quot;Add three more paragraphs.&quot;"], answer:1, explain:"<strong>&quot;Keep the length and audience the same, but make the tone a bit more casual.&quot;</strong> preserves the parts already working and adjusts only the tone, which is efficient.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>&quot;Redo everything from scratch.&quot;</b>: redoing everything risks losing the improvements you already secured.</span><span class='qd'><b>&quot;Change the audience and the length too.&quot;</b>: changing settings that already work can undo good results.</span><span class='qd'><b>&quot;Add three more paragraphs.&quot;</b>: adding length ignores the actual issue, which is tone.</span>" },
  { id:"D4-099", domain:4, obj:"4.4", diff:"hard", q:"You ask the AI to critique its own answer, and it produces a thoughtful list of weaknesses. What is the BEST way to turn that critique into a better final product?", options:["Thank the AI and keep the original unchanged","Ask the AI to critique the critique endlessly","Ask the AI to revise the answer specifically to address each weakness it identified","Discard both the answer and the critique"], answer:2, explain:"<strong>Ask the AI to revise the answer specifically to address each weakness it identified</strong> converts the self-critique into concrete improvements.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Thank the AI and keep the original unchanged</b>: leaving the answer unchanged wastes the critique.</span><span class='qd'><b>Ask the AI to critique the critique endlessly</b>: endless meta-critique produces no improved product.</span><span class='qd'><b>Discard both the answer and the critique</b>: discarding everything throws away useful work and insight.</span>" },
  { id:"D4-100", domain:4, obj:"4.5", diff:"hard", q:"You are near the end of a long, successful chained project in one thread. You want to reuse the final approach for a similar future project. What is the BEST closing move?", options:["Delete the thread so no one can see it","Stop using AI for future projects","Immediately dump the next unrelated project into this same thread","Ask the AI to summarize the final approach and key decisions so you can seed a clean new thread later"], answer:3, explain:"<strong>Ask the AI to summarize the final approach and key decisions so you can seed a clean new thread later</strong> captures the reusable essence while keeping future work uncluttered.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Delete the thread so no one can see it</b>: deleting it discards the very approach you want to reuse.</span><span class='qd'><b>Immediately dump the next unrelated project into this same thread</b>: piling a new project onto a long thread invites context bleed and confusion.</span><span class='qd'><b>Stop using AI for future projects</b>: abandoning AI contradicts your goal of reusing the successful approach.</span>" }
);
